#include <stdio.h>
#include <stdbool.h>
#include <pthread.h>
#include <unistd.h>

/* ==========================================
 * HARDWARE SYNCHRONIZATION PRIMITIVES
 * ==========================================
 */

/*
 * Test-and-Set (TAS) Instruction
 * Atomically: old = *target; *target = TRUE; return old;
 * In real hardware, this is a single CPU instruction
 * On x86: XCHG instruction
 * On ARM: SWP instruction
 */
bool test_and_set(bool *target) {
 bool old_value = *target; // Save old value
 *target = true; // Set to TRUE atomically
 return old_value; // Return old value
}

/*
 * Compare-and-Swap (CAS) Instruction
 * Atomically: if (*value == expected) { *value = new_value; return old; }
 * In real hardware:
 * x86: CMPXCHG instruction
 * ARM: LDREX/STREX pair
 */
int compare_and_swap(int *value, int expected, int new_value) {
 int temp = *value; // Save current value
 if (*value == expected) { // Check if matches expected
 *value = new_value; // Conditional update
 }
 return temp; // Return original value
}

/* ==========================================
 * MUTUAL EXCLUSION USING TEST_AND_SET
 * ==========================================
 */

volatile bool lock = false; // Shared lock variable
volatile int counter = 0; // Shared counter for demonstration

void* process_with_tas(void* arg) {
 int thread_id = *(int*)arg;

 for (int i = 0; i < 1000; i++) {
 // Busy wait until lock is free
 while (test_and_set(&lock)) {
 // Spin - lock was already held
 }

 // === CRITICAL SECTION START ===
 counter++; // Safe to modify shared variable
 // === CRITICAL SECTION END ===

 lock = false; // Release the lock
 }

 return NULL;
}

/* ==========================================
 * MUTUAL EXCLUSION USING COMPARE_AND_SWAP
 * ==========================================
 */

volatile int cas_lock = 0; // 0 = free, 1 = locked

void acquire_cas_lock() {
 while (compare_and_swap(&cas_lock, 0, 1) != 0) {
 // Spin - lock was not free (was already 1)
 }
}

void release_cas_lock() {
 cas_lock = 0;
}

void* process_with_cas(void* arg) {
 int thread_id = *(int*)arg;

 for (int i = 0; i < 1000; i++) {
 // Try to acquire lock using CAS
 // Only succeeds if lock == 0 (free)
 while (compare_and_swap(&cas_lock, 0, 1) != 0) {
 // Spin waiting for lock
 }

 // === CRITICAL SECTION START ===
 counter++; // Safe to modify shared variable
 // === CRITICAL SECTION END ===

 release_cas_lock(); // Release lock
 }

 return NULL;
}

/* ==========================================
 * LOCK-FREE COUNTER USING CAS
 * ==========================================
 */

volatile int lock_free_counter = 0;

// Increment without locks - uses compare-and-swap
void lock_free_increment() {
 int old_value, new_value;
 do {
 old_value = lock_free_counter; // Read current value
 new_value = old_value + 1; // Compute new value
 // Try to swap: if value hasn't changed, update it
 // If value changed (by another thread), retry
 } while (compare_and_swap(&lock_free_counter, old_value, new_value) != old_value);
}

void* process_lock_free(void* arg) {
 for (int i = 0; i < 1000; i++) {
 lock_free_increment();
 }
 return NULL;
}

/* ==========================================
 * MAIN - TEST ALL IMPLEMENTATIONS
 * ==========================================
 */

void test_implementation(const char* name, void* (*worker)(void*), int num_threads) {
 pthread_t threads[10];
 int ids[10];

 counter = 0; // Reset counter

 // Create threads
 for (int i = 0; i < num_threads; i++) {
 ids[i] = i;
 pthread_create(&threads[i], NULL, worker, &ids[i]);
 }

 // Wait for completion
 for (int i = 0; i < num_threads; i++) {
 pthread_join(threads[i], NULL);
 }

 printf("%s: counter = %d (expected %d) - %s\n", 
 name, counter, num_threads * 1000,
 counter == num_threads * 1000 ? "PASS" : "FAIL");
}

int main() {
 const int NUM_THREADS = 5;

 printf("=== Hardware Synchronization Demo ===\n\n");

 printf("Test 1: Test-and-Set Mutual Exclusion\n");
 test_implementation("TAS", process_with_tas, NUM_THREADS);

 printf("\nTest 2: Compare-and-Swap Mutual Exclusion\n");
 test_implementation("CAS", process_with_cas, NUM_THREADS);

 printf("\nTest 3: Lock-Free Counter (CAS loop)\n");
 lock_free_counter = 0;
 pthread_t threads[10];
 int ids[10];

 for (int i = 0; i < NUM_THREADS; i++) {
 ids[i] = i;
 pthread_create(&threads[i], NULL, process_lock_free, &ids[i]);
 }

 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(threads[i], NULL);
 }

 printf("Lock-Free: counter = %d (expected %d) - %s\n", 
 lock_free_counter, NUM_THREADS * 1000,
 lock_free_counter == NUM_THREADS * 1000 ? "PASS" : "FAIL");

 return 0;
}
